let store = flow.get('store') || {};
let parts = msg.topic.split("/");

let current = store;
for (let i = 0; i < parts.length - 1; i++) {
    if (!current[parts[i]]) current[parts[i]] = {};
    current = current[parts[i]];
}

let value;
if (!isNaN(msg.payload) && msg.payload !== "") value = Number(msg.payload);
else if (msg.payload === "true" || msg.payload === "false") value = msg.payload === "true";
else value = msg.payload;

current[parts[parts.length - 1]] = value;

flow.set('store', store);
return msg;

let site_id = "Site1";
let store = flow.get('store');
if (!store) return null;

let tank = store["Enterprise B"]
    ?.[site_id]
    ?.liquidprocessing
    ?.tankstorage01
    ?.tank01;

if (!tank?.metric || !tank?.lotnumber) return null;

let row = {
    dbms: "enterpriseb",
    table: "kpi",
    timestamp: flow.get(`ts_${site_id}`) || flow.get('factory_timestamp') || new Date().toISOString(),
    site: site_id,
    lotnumberid: tank.lotnumber.lotnumber,
    oee: tank.metric.oee,
    performance: tank.metric.performance,
    quality: tank.metric.quality,
    availability: tank.metric.availability
};

msg.payload = JSON.stringify([row]);
return msg;

